Actionscript.script:
function 显示运营图标(名字)
{
	图标HOT = [];
	图标打折 = [];
	图标NEW = [];
	图标半价 = [];
	图标一折 = [];
	var _loc2_ = 0;
	while (_loc2_ < 图标NEW.length)
	{
		if (名字 == 图标NEW[_loc2_])
		{
			return "图标NEW";
		}
		_loc2_ += 1;
	}
	_loc2_ = 0;
	while (_loc2_ < 图标HOT.length)
	{
		if (名字 == 图标HOT[_loc2_])
		{
			return "图标HOT";
		}
		_loc2_ += 1;
	}
	_loc2_ = 0;
	while (_loc2_ < 图标打折.length)
	{
		if (名字 == 图标打折[_loc2_])
		{
			return "图标打折";
		}
		_loc2_ += 1;
	}
	_loc2_ = 0;
	while (_loc2_ < 图标半价.length)
	{
		if (名字 == 图标半价[_loc2_])
		{
			return "图标半价";
		}
		_loc2_ += 1;
	}
	_loc2_ = 0;
	while (_loc2_ < 图标一折.length)
	{
		if (名字 == 图标一折[_loc2_])
		{
			return "图标一折";
		}
		_loc2_ += 1;
	}
	return "无";
}
function 按类别筛选(s)
{
	temp = new Array();
	var _loc3_ = 0;
	while (_loc3_ < _root.商城商品总数组.length)
	{
		if (_root.商城商品总数组[_loc3_][2] == s)
		{
			temp.push(_root.商城商品总数组[_loc3_]);
		}
		_loc3_ += 1;
	}
	return temp;
}
function 刷新购物清单(arr)
{
	if (shopCart.shopCartContent != undefined)
	{
		removeMovieClip(shopCart.shopCartContent);
		delete undefined;
		//§§push(undefined);
	}
	shopCart.createEmptyMovieClip("shopCartContent",shopCart.getNextHighestDepth());
	shopCart.shopCartContent.setMask(shopCart.mask2);
	var _loc3_ = 0;
	while (_loc3_ < arr.length)
	{
		shopCart.shopCartContent.attachMovie("shopTab3","tab" + _loc3_.toString(),shopCart.shopCartContent.getNextHighestDepth(),{item:arr[_loc3_]});
		shopCart.shopCartContent["tab" + _loc3_.toString()]._y = shopCart.mask2._y + 40 * _loc3_;
		shopCart.shopCartContent["tab" + _loc3_.toString()]._x = shopCart.mask2._x;
		_loc3_ += 1;
	}
	shopCart.获得页数();
	_root.保存购物车();
}
function 刷新已买显示(arr)
{
	if (shopCart.shopCartContent != undefined)
	{
		removeMovieClip(shopCart.shopCartContent);
		delete undefined;
		//§§push(undefined);
	}
	shopCart.createEmptyMovieClip("shopCartContent",shopCart.getNextHighestDepth());
	shopCart.shopCartContent.setMask(shopCart.mask2);
	var _loc2_ = 0;
	while (_loc2_ < arr.length)
	{
		shopCart.shopCartContent.attachMovie("shopTab2","tab" + _loc2_.toString(),shopCart.shopCartContent.getNextHighestDepth(),{item:arr[_loc2_]});
		shopCart.shopCartContent["tab" + _loc2_.toString()]._y = shopCart.mask2._y + 40 * _loc2_;
		shopCart.shopCartContent["tab" + _loc2_.toString()]._x = shopCart.mask2._x + 10;
		_loc2_ += 1;
	}
	shopCart.获得页数();
}
function 组装已经购买物品(shopid)
{
	var _loc3_ = [];
	var _loc4_ = 0;
	var _loc5_ = _root.商城商品总数组.length;
	while (_loc4_ < _loc5_)
	{
		if (shopid == _root.商城商品总数组[_loc4_][0])
		{
			_loc3_ = _root.商城商品总数组[_loc4_];
			break;
		}
		_loc4_ += 1;
	}
	return _loc3_;
}
function 刷新已买清单()
{
	var _loc2_ = new Array();
	var _loc3_ = 0;
	while (_loc3_ < _root.商城已购买物品.length)
	{
		var _loc4_ = new Array();
		var _loc5_ = 组装已经购买物品(_root.商城已购买物品[_loc3_][0]);
		_loc4_.push(_loc5_[0]);
		_loc4_.push(_loc5_[1]);
		_loc4_.push(_loc5_[2]);
		_loc4_.push(_loc5_[3]);
		_loc4_.push("11084055");
		_loc4_.push(_root.商城已购买物品[_loc3_][4]);
		_loc2_.push(_loc4_);
		_loc3_ += 1;
	}
	this.刷新已买显示(_loc2_);
	_root.清单load状态(false);
}
function checkItem(s)
{
	var _loc2_ = 0;
	while (_loc2_ < bill.length)
	{
		if (bill[_loc2_].id == s.id)
		{
			return _loc2_;
		}
		_loc2_ += 1;
	}
	return -1;
}
function checkAndRemove(s)
{
	n = checkItem(s);
	if (n != -1)
	{
		if (bill[n].quantity > 1)
		{
			bill[n].quantity--;
		}
		else
		{
			bill.splice(n,1);
		}
	}
}
