function getTimeMilliseconds()
{
	now_date = new Date();
	now_milliseconds = (now_date.getHours() * 3600 + now_date.getMinutes() * 60 + now_date.getSeconds()) * 1000 + now_date.getMilliseconds();
	return now_milliseconds;
}
function 根据数字得商品类别(数字)
{
	var _loc2_ = "";
	数字 += "";
	switch (数字)
	{
		case "1" :
			_loc2_ = "特价商品";
			break;
		case "2" :
			_loc2_ = "新品推荐";
			break;
		case "3" :
			_loc2_ = "必备弹夹";
			break;
		case "4" :
			_loc2_ = "常用材料";
			break;
		case "5" :
			_loc2_ = "酷炫长枪";
			break;
		case "6" :
			_loc2_ = "逼格手枪";
			break;
		case "7" :
			_loc2_ = "实战冷兵";
			break;
		case "8" :
			_loc2_ = "精良护头";
			break;
		case "9" :
			_loc2_ = "精良胸甲";
			break;
		case "10" :
			_loc2_ = "精良手甲";
			break;
		case "11" :
			_loc2_ = "精良腿甲";
			break;
		case "12" :
			_loc2_ = "精良战靴";
			break;
		case "13" :
			_loc2_ = "特效胶囊";
			break;
		case "14" :
			_loc2_ = "极品装备";
			break;
		case "15" :
			_loc2_ = "非卖品";
	}
	return _loc2_;
}
function 刷新商城人物装扮(目标)
{
	var 目标 = this.展示框[目标];
	tmp_aaa = _root.根据物品名查找属性(目标.头部装备, 14);
	if (tmp_aaa[0] == "true")
	{
		目标.发型 = "";
	}
	else
	{
		目标.发型 = 目标.发型;
	}
	目标.面具 = _root.根据物品名查找属性(目标.头部装备, 15);
	目标.身体 = 目标.性别 + _root.根据物品名查找属性(目标.上装装备, 15) + "身体";
	目标.上臂 = 目标.性别 + _root.根据物品名查找属性(目标.上装装备, 15) + "上臂";
	目标.左下臂 = 目标.性别 + _root.根据物品名查找属性(目标.上装装备, 15) + "左下臂";
	目标.右下臂 = 目标.性别 + _root.根据物品名查找属性(目标.上装装备, 15) + "右下臂";
	目标.左手 = _root.根据物品名查找属性(目标.手部装备, 15) + "左手";
	目标.右手 = _root.根据物品名查找属性(目标.手部装备, 15) + "右手";
	目标.屁股 = 目标.性别 + _root.根据物品名查找属性(目标.下装装备, 15) + "屁股";
	目标.左大腿 = 目标.性别 + _root.根据物品名查找属性(目标.下装装备, 15) + "左大腿";
	目标.右大腿 = 目标.性别 + _root.根据物品名查找属性(目标.下装装备, 15) + "右大腿";
	目标.小腿 = 目标.性别 + _root.根据物品名查找属性(目标.下装装备, 15) + "小腿";
	目标.脚 = _root.根据物品名查找属性(目标.脚部装备, 15);
	目标.刀_装扮 = _root.根据物品名查找属性(目标.刀, 15);
	目标.长枪_装扮 = _root.根据物品名查找属性(目标.长枪, 15);
	目标.手枪_装扮 = _root.根据物品名查找属性(目标.手枪, 15);
	目标.手枪2_装扮 = _root.根据物品名查找属性(目标.手枪2, 15);
	目标.手雷_装扮 = _root.根据物品名查找属性(目标.手雷, 15);
	目标.gotoAndPlay("刷新装扮");
}

bill = new Array();
shopList.mask._visible = false;
this.shopList.makeList = function(arr)
{
	临时商品列表 = arr;
	if (临时商品列表.length < 7)
	{
		shopList.商城列表滚动条._visible = false;
	}
	else
	{
		shopList.商城列表滚动条._visible = true;
	}
	shopList.makeList2();
};
this.shopList.makeList2 = function()
{
	筛选表 = 按类别筛选(当前页面);
	if (筛选表.length < 7)
	{
		this.shopList.商城列表滚动条._visible = false;
	}
	else
	{
		this.shopList.商城列表滚动条._visible = true;
	}
	if (this.shopListContent != undefined)
	{
		removeMovieClip(this.shopListContent);
	}
	this.createEmptyMovieClip("shopListContent",this.getNextHighestDepth());
	this.shopListContent._x = 0;
	this.shopListContent._y = 0;
	this.shopListContent.setMask(shopList.mask);
	var _loc3_ = 0;
	while (_loc3_ < 筛选表.length)
	{
		temp = 筛选表[_loc3_];
		this.shopListContent.attachMovie("shopTab","tab" + _loc3_.toString(),this.shopListContent.getNextHighestDepth(),{item:temp, _x:this.定位器._x, _y:this.定位器._y + _loc3_ * 50});
		this.获得页数();
		_loc3_ += 1;
	}
};
this.shopList.makeList3 = function(领取物品表)
{
	if (领取物品表.length < 7)
	{
		shopList.商城列表滚动条._visible = false;
	}
	else
	{
		shopList.商城列表滚动条._visible = true;
	}
	if (this.shopListContent != undefined)
	{
		removeMovieClip(this.shopListContent);
	}
	this.createEmptyMovieClip("shopListContent",this.getNextHighestDepth());
	this.shopListContent._x = shopList.mask._x;
	this.shopListContent._y = shopList.mask._y;
	this.shopListContent.setMask(shopList.mask);
	var _loc3_ = 0;
	while (_loc3_ < 领取物品表.length)
	{
		temp = 领取物品表[_loc3_];
		this.shopListContent.attachMovie("shopTab2","tab" + _loc3_.toString(),this.shopListContent.getNextHighestDepth(),{item:temp});
		this.shopListContent["tab" + _loc3_.toString()]._y = _loc3_ * 50;
		_loc3_ += 1;
	}
};
shopCart.refreshCart = function()
{
	this.btnUP._alpha = 30;
	this.btnDown._alpha = 30;
};
shopCtg.createEmptyMovieClip("shopCtgContent",this.getNextHighestDepth());
shopCtg.shopCtgContent._x = shopCtg.mask3._x;
shopCtg.shopCtgContent._y = shopCtg.mask3._y;
this.shopCtg.makeCtg = function(arr)
{
	var _loc3_ = 0;
	while (_loc3_ < arr.length)
	{
		this.shopCtgContent.attachMovie("shopCtgBtn","btn" + _loc3_.toString(),this.shopCtgContent.getNextHighestDepth(),{btnName:arr[_loc3_]});
		this.shopCtgContent["btn" + _loc3_.toString()]._x = 0;
		this.shopCtgContent["btn" + _loc3_.toString()]._y = 5 + 25 * _loc3_;
		_loc3_ += 1;
	}
};

function 关闭商城(){
	_root.保存购物车();
	_root.商城主mc = null;
	_root.卸载全屏UI();
	_root.自动存盘();
}

购物倍数 = 1;
临时商品列表 = new Array();
当前页面 = "常用物品";
_root.获取购物车信息();
_root.主体load状态(true);
var temp = new Array();
var arrSend = new Array();
var loop = 0;
while (loop < _root.kshop_list.length)
{
	temp = [];
	temp.push(_root.kshop_list[loop].id);
	temp.push(_root.kshop_list[loop].item);
	temp.push(_root.kshop_list[loop].type);
	temp.push(_root.kshop_list[loop].price);
	arrSend.push(temp);
	loop++;
}

_root.商城主mc = this;
_root.商城商品总数组 = arrSend;
this.shopList.makeList(arrSend);
_root.主体load状态(false);
_root.获取虚拟币值();
_root.读盘商城已购买物品();
this.刷新购物清单(_root.商城购物车);

_root.购物车总价 = _root.获取购物车总价();
shopCtg.makeCtg(["新品推荐", "必备弹夹", "常用材料", "酷炫长枪", "逼格手枪", "实战冷兵", "精良护头", "精良胸甲", "精良手甲", "精良腿甲", "精良战靴", "特效胶囊", "极品装备", "非卖品"]);
gotoAndStop("商城");

_root.获取虚拟币值();
_root.商城主mc.刷新购物清单();
_root.购物车总价 = _root.获取购物车总价();
_root.商城主mc.刷新购物清单(_root.商城购物车);
gotoAndStop("商城");

on(release){
   _parent.展示框._visible = 1;
}
onClipEvent(load){
   显示文字 = _root.获得翻译("打开预览窗");
}
on(rollOver){
   _root.注释(150,显示文字);
}
on(rollOut){
   _root.注释结束();
}
